171	        match self {
172	            Self::Handshake(_) => 0x0000,
173	            Self::KeepAlive => 0x0001,
174	            Self::Ack(_) => 0x0002,
175	            Self::Nak(_) => 0x0003,
176	            Self::Shutdown => 0x0005,
177	            Self::Ack2 => 0x0006,
178	            Self::MsgDropRequest(_) => 0x0007,
179	            Self::UserDefined => 0x7fff,
180	        }
