184	        match self {
185	            Self::Handshake(hs) => hs.serialize(),
186	            Self::Ack(ack) => ack.serialize(),
187	            Self::Nak(nak) => nak.serialize(),
188	            Self::MsgDropRequest(drop) => drop.serialize(),
189	            _ => vec![],
190	        }
191	    }
