193	    pub fn deserialize(raw_control_packet: &[u8]) -> Result<Self> {
194	        let type_id = u16::from_be_bytes(raw_control_packet[0..2].try_into().unwrap()) & 0x7FFF;
195	        let packet = match type_id {
196	            0x0000 => Self::Handshake(HandShakeInfo::deserialize(&raw_control_packet[16..])?),
197	            0x0001 => Self::KeepAlive,
198	            0x0002 => Self::Ack(AckInfo::deserialize(&raw_control_packet[16..])?),
199	            0x0003 => Self::Nak(NakInfo::deserialize(&raw_control_packet[16..])?),
200	            0x0005 => Self::Shutdown,
201	            0x0006 => Self::Ack2,
202	            0x0007 => {
203	                Self::MsgDropRequest(DropRequestInfo::deserialize(&raw_control_packet[16..])?)
204	            }
205	            0x7fff => Self::UserDefined,
206	            _ => {
207	                return Err(Error::new(
208	                    ErrorKind::InvalidData,
209	                    "unknown control packet type",
210	                ));
211	            }
212	        };
213	        Ok(packet)
214	    }
