278	pub(crate) struct AckInfo {
279	    /// The packet sequence number to which all the
280	    /// previous packets have been received (excluding)
281	    pub next_seq_number: SeqNumber,
282	    pub info: Option<AckOptionalInfo>,
283	}
284	
285	impl AckInfo {
286	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
287	        let get_u32 =
288	            |idx: usize| u32::from_be_bytes(raw[(idx * 4)..(idx + 1) * 4].try_into().unwrap());
289	
290	        let next_seq_number: SeqNumber = get_u32(0).into();
291	
292	        if raw.len() <= 4 {
293	            return Ok(Self {
294	                next_seq_number,
295	                info: None,
296	            });
297	        }
298	        let info = AckOptionalInfo {
299	            rtt: get_u32(1),
300	            rtt_variance: get_u32(2),
301	            available_buf_size: get_u32(3),
302	            pack_recv_rate: get_u32(4),
303	            link_capacity: get_u32(5),
304	        };
305	        Ok(Self {
306	            next_seq_number,
307	            info: Some(info),
308	        })
309	    }
310	
311	    pub fn serialize(&self) -> Vec<u8> {
312	        match &self.info {
313	            None => self.next_seq_number.number().to_be_bytes().to_vec(),
314	            Some(extra) => [
315	                self.next_seq_number.number(),
316	                extra.rtt,
317	                extra.rtt_variance,
318	                extra.available_buf_size,
319	                extra.pack_recv_rate,
320	                extra.link_capacity,
321	            ]
322	            .iter()
323	            .flat_map(|v| v.to_be_bytes())
324	            .collect(),
325	        }
326	    }
327	}
