344	impl NakInfo {
345	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
346	        let losses: Vec<u32> = raw
347	            .chunks(4)
348	            .filter_map(|chunk| {
349	                if chunk.len() < 4 {
350	                    return None;
351	                }
352	                Some(u32::from_be_bytes(chunk.try_into().unwrap()))
353	            })
354	            .collect();
355	        Ok(Self { loss_info: losses })
356	    }
357	
358	    pub fn serialize(&self) -> Vec<u8> {
359	        self.loss_info
360	            .iter()
361	            .flat_map(|x| x.to_be_bytes())
362	            .collect()
363	    }
364	}
