367	pub(crate) struct DropRequestInfo {
368	    pub first_seq_number: SeqNumber,
369	    pub last_seq_number: SeqNumber,
370	}
371	
372	impl DropRequestInfo {
373	    pub fn deserialize(raw: &[u8]) -> Result<Self> {
374	        let get_u32 =
375	            |idx: usize| u32::from_be_bytes(raw[(idx * 4)..(idx + 1) * 4].try_into().unwrap());
376	
377	        Ok(Self {
378	            first_seq_number: get_u32(0).into(),
379	            last_seq_number: get_u32(1).into(),
380	        })
381	    }
382	
383	    pub fn serialize(&self) -> Vec<u8> {
384	        [
385	            self.first_seq_number.number(),
386	            self.last_seq_number.number(),
387	        ]
388	        .iter()
389	        .flat_map(|x| x.to_be_bytes())
390	        .collect()
391	    }
