986	            return Err(Error::new(
987	                ErrorKind::InvalidInput,
988	                "socket needs to be configured in stream mode to send data buffer",
989	            ));
990	        }
991	        if self.status() != UdtStatus::Connected {
992	            return Err(Error::new(
993	                ErrorKind::NotConnected,
994	                "UDT socket is not connected",
995	            ));
996	        }
997	
998	        if data.is_empty() {
999	            return Ok(());
1000	        }
