1002	        if self.snd_buffer.lock().unwrap().is_empty() {
1003	            // delay the EXP timer to avoid mis-fired timeout
1004	            self.state().last_rsp_time = Instant::now();
1005	        }
1006	
1007	        self.snd_buffer
1008	            .lock()
1009	            .unwrap()
1010	            .add_message(data, None, false)?;
1011	        self.update_snd_queue(false);
1012	        Ok(())
1013	    }
