1015	    pub async fn recv(&self, buf: &mut [u8]) -> Result<usize> {
1016	        if self.socket_type != SocketType::Stream {
1017	            return Err(Error::new(
1018	                ErrorKind::InvalidInput,
1019	                "cannot recv on non-stream socket",
1020	            ));
1021	        }
1022	        let status = self.status();
1023	        if !status.is_alive() {
1024	            if !self.rcv_buffer().has_data_to_read() {
1025	                return Err(Error::new(
1026	                    ErrorKind::BrokenPipe,
1027	                    "connection was closed or broken",
1028	                ));
1029	            }
1030	        } else if status != UdtStatus::Connected {
1031	            return Err(Error::new(
1032	                ErrorKind::NotConnected,
1033	                "UDT socket not connected",
1034	            ));
1035	        }
1036	
1037	        if buf.is_empty() {
1038	            return Ok(0);
1039	        }
1040	
1041	        self.wait_for_data_to_read().await;
1042	
1043	        let status = self.status();
1044	        if !status.is_alive() {
1045	            if !self.rcv_buffer().has_data_to_read() {
1046	                return Err(Error::new(
1047	                    ErrorKind::BrokenPipe,
1048	                    "connection was closed or broken",
1049	                ));
1050	            }
1051	        } else if status != UdtStatus::Connected {
1052	            return Err(Error::new(
1053	                ErrorKind::NotConnected,
1054	                "UDT socket not connected",
1055	            ));
1056	        }
1057	
1058	        let mut buf = ReadBuf::new(buf);
1059	        let written = self.rcv_buffer().read_buffer(&mut buf);
1060	
1061	        // TODO: implement configurable UDT timeout
1062	        Ok(written)
1063	    }
