1098	    pub(crate) async fn connect(
1099	        &self,
1100	        addr: SocketAddr,
1101	        bind_addr: Option<SocketAddr>,
1102	    ) -> Result<()> {
1103	        if self.status() != UdtStatus::Init {
1104	            return Err(Error::new(
1105	                ErrorKind::Unsupported,
1106	                format!("expected status Init, found {:?}", self.status),
1107	            ));
1108	        }
1109	
1110	        self.open();
1111	        {
1112	            let mut udt = Udt::get().write().await;
1113	            udt.update_mux(self, bind_addr).await?;
1114	        }
1115	
1116	        *self.status.lock().unwrap() = UdtStatus::Connecting;
1117	        self.set_peer_addr(addr);
1118	
1119	        // TODO: register the current socket in the rendezvous queue
1120	        // This is used to temporarily store incoming handshakes and possibly retry connections, including for non-rendezvous connections.
1121	
1122	        let hs_packet = {
1123	            let configuration = self.configuration.read().unwrap();
1124	            let hs = HandShakeInfo {
1125	                udt_version: configuration.udt_version(),
1126	                initial_seq_number: self.initial_seq_number,
1127	                max_packet_size: configuration.mss,
1128	                max_window_size: std::cmp::min(
1129	                    self.flow.read().unwrap().flow_window_size,
1130	                    self.rcv_buffer().get_available_buf_size(),
1131	                ),
1132	                connection_type: 1,
1133	                socket_type: self.socket_type,
1134	                socket_id: self.socket_id,
1135	                ip_address: addr.ip(),
1136	                syn_cookie: 0,
1137	            };
1138	            UdtControlPacket::new_handshake(hs, 0)
1139	        };
1140	        self.send_to(&addr, hs_packet.into()).await?;
1141	
1142	        Ok(())
1143	    }
