1205	    pub(crate) async fn wait_for_data_to_read(&self) {
1206	        if let Some(notified) = {
1207	            let status = self.status.lock().unwrap();
1208	            if !status.is_alive() {
1209	                None
1210	            } else {
1211	                let rcv_buffer = self.rcv_buffer();
1212	                if rcv_buffer.has_data_to_read() {
1213	                    None
1214	                } else {
1215	                    Some(self.rcv_notify.notified())
1216	                }
1217	            }
1218	        } {
1219	            notified.await
1220	        }
1221	    }
