1224	        if let Some(notified) = {
1225	            let status = self.status.lock().unwrap();
1226	            if *status != UdtStatus::Connecting {
1227	                None
1228	            } else {
1229	                Some(self.connect_notify.notified())
1230	            }
1231	        } {
1232	            notified.await
1233	        }
1234	        self.status()
1235	    }
