1237	    pub(crate) async fn wait_for_next_ack_or_empty_snd_buffer(&self) {
1238	        if let Some(notified) = {
1239	            let snd_buffer = self.snd_buffer.lock().unwrap();
1240	            if snd_buffer.is_empty() {
1241	                None
1242	            } else {
1243	                Some(self.ack_notify.notified())
1244	            }
1245	        } {
1246	            notified.await
1247	        }
1248	    }
1249	}
